frappe.ui.form.on('Stock Entry Detail', {
    items_add: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];

        if (frm.doc.stock_entry_type === "Material Transfer") {
            if (frm.doc.custom_default_employee_function && !row.employee_function) {
                frappe.model.set_value(cdt, cdn, 'employee_function', frm.doc.custom_default_employee_function);
            }
            if (frm.doc.custom_target_employee_function && !row.to_employee_function) {
                frappe.model.set_value(cdt, cdn, 'to_employee_function', frm.doc.custom_target_employee_function);
            }
        }
    }
});

function set_employee_function_mandatory(frm) {
    const isMaterialTransfer = frm.doc.stock_entry_type === "Material Transfer";
    const isMaterialConsumption = frm.doc.stock_entry_type === "Material Consumption";

    if (isMaterialTransfer) {
        frm.set_df_property('custom_target_employee_function', 'reqd', 1);
        frm.set_df_property('to_warehouse', 'reqd', 1);

        if (frm.fields_dict['items'] && frm.fields_dict['items'].grid) {
            frm.fields_dict['items'].grid.docfields.forEach(df => {
                if (['employee_function', 'to_employee_function'].includes(df.fieldname)) {
                    df.reqd = 1;
                }
            });
            frm.fields_dict['items'].grid.refresh();
        }
    } 
    else if (isMaterialConsumption) {
        frm.set_df_property('from_warehouse', 'reqd', 1);

        if (frm.fields_dict['items'] && frm.fields_dict['items'].grid) {
            frm.fields_dict['items'].grid.docfields.forEach(df => {
                if (df.fieldname === 'custom_employee_functions') {
                    df.reqd = 1;
                }
            });
            frm.fields_dict['items'].grid.refresh();
        }
    } 
    else {
        frm.set_df_property('custom_default_employee_function', 'reqd', 0);
        frm.set_df_property('custom_target_employee_function', 'reqd', 0);

        if (frm.fields_dict['items'] && frm.fields_dict['items'].grid) {
            frm.fields_dict['items'].grid.docfields.forEach(df => {
                if (['employee_function', 'to_employee_function'].includes(df.fieldname)) {
                    df.reqd = 0;
                }
            });
            frm.fields_dict['items'].grid.refresh();
        }
    }
}

frappe.ui.form.on("Stock Entry Detail", {
    item_code: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.item_code) {
            frappe.db.get_value("Item", row.item_code, "custom_inspection_required_before_manufacturing", (r) => {
                if (r && r.custom_inspection_required_before_manufacturing) {
                    frm.set_value("inspection_required", 1);
                } else {
                    // check if any other item in the table still requires inspection
                    let requires_inspection = false;
                    frm.doc.items.forEach(d => {
                        if (d.item_code) {
                            frappe.db.get_value("Item", d.item_code, "custom_inspection_required_before_manufacturing", (rr) => {
                                if (rr && rr.custom_inspection_required_before_manufacturing) {
                                    requires_inspection = true;
                                }
                            });
                        }
                    });
                    // small delay to ensure db lookups complete
                    setTimeout(() => {
                        if (!requires_inspection) {
                            frm.set_value("inspection_required", 0);
                        }
                    }, 300);
                }
            });
        }
    },

    // Handle remove item case
    items_remove: function(frm) {
        let requires_inspection = false;
        let pending = frm.doc.items.length;

        if (pending === 0) {
            frm.set_value("inspection_required", 0);
            return;
        }

        frm.doc.items.forEach(d => {
            frappe.db.get_value("Item", d.item_code, "custom_inspection_required_before_manufacturing", (r) => {
                if (r && r.custom_inspection_required_before_manufacturing) {
                    requires_inspection = true;
                }
                pending--;
                if (pending === 0) {
                    frm.set_value("inspection_required", requires_inspection ? 1 : 0);
                }
            });
        });
    }
});

frappe.ui.form.on('Stock Entry', {
    refresh: function (frm) {
        toggle_manbatch_table(frm);

        frm.fields_dict['items'].grid.wrapper.on(
            'change',
            '.input-with-feedback[data-fieldname="custom_enable_manufacturing_batch"]',
            function () {
                toggle_manbatch_table(frm);
            }
        );
    },

    onload_post_render: function (frm) {
        toggle_manbatch_table(frm);
    },

    before_save: function (frm) {
        let promises = [];

        (frm.doc.custom_manufacture_batch || []).forEach(row => {
            let patient = frm.doc.custom_patient_;
            row.patient = patient;

            // Find finished item
            let finished_item = '';
            (frm.doc.items || []).forEach(item => {
                if (item.is_finished_item) {
                    finished_item = item.item_code;
                }
            });
            row.item = finished_item;

            // ✅ Validate Expiry Date is mandatory
            if (!row.expired_date) {
                frappe.throw(__("Expiry Date is mandatory to create a Batch."));
            }

            // ✅ Validate Manufacture Date is mandatory
            if (!row.manufacture_date) {
                frappe.throw(__("Manufacture Date is mandatory to create a Batch."));
            }

            // ✅ Validate that Manufacture Date is before Expiry Date
            let mfg_date = frappe.datetime.str_to_obj(row.manufacture_date);
            let exp_date = frappe.datetime.str_to_obj(row.expired_date);
            
            if (mfg_date >= exp_date) {
                frappe.throw(__("Manufacture Date must be before Expiry Date."));
            }

            // ✅ Validate that Expiry Date is in the future
            let today = frappe.datetime.now_date();
            if (row.expired_date < today) {
                frappe.throw(__("Expiry Date cannot be in the past."));
            }

            if (row.manufacture_date && row.manufacture_batch) {
                let finished_item_row = null;
                (frm.doc.items || []).forEach(item => {
                    if (item.is_finished_item) {
                        finished_item_row = item;
                    }
                });

                if (!finished_item) {
                    frappe.throw(__("No finished item found. Cannot create batch."));
                    return;
                }

                let batch_id = row.manufacture_batch;
                if (!batch_id) {
                    frappe.throw(__("Manufacture Batch ID is required."));
                    return;
                }

                // ✅ Only create batch if not already linked
                if (!finished_item_row.batch_no) {
                    let promise = new Promise((resolve, reject) => {
                        // ✅ First, check if the item has batch enabled
                        frappe.db.get_value("Item", finished_item, ["has_batch_no", "item_name"]).then(item_result => {
                            if (!item_result.message || !item_result.message.has_batch_no) {
                                // ❌ Item does not have batch tracking enabled
                                frappe.msgprint({
                                    title: __('Batch Not Enabled'),
                                    indicator: 'red',
                                    message: __(`The finished item "${item_result.message?.item_name || finished_item}" must have "Has Batch No" enabled in the Item master to create batches.`)
                                });
                                reject();
                                return;
                            }

                            // ✅ Item has batch enabled, now check if batch already exists
                            frappe.db.get_value("Batch", {
                                "batch_id": batch_id,
                                "item": finished_item
                            }, "name").then(result => {
                                if (result.message && result.message.name) {
                                    // ❌ Batch already exists → throw error
                                    frappe.throw(__(`Batch ID "${batch_id}" already exists for item "${finished_item}". Please use a different Batch ID.`));
                                    reject();
                                } else {
                                    frappe.call({
                                        method: "frappe.client.insert",
                                        args: {
                                            doc: {
                                                doctype: "Batch",
                                                batch_id: batch_id,
                                                manufacturing_date: row.manufacture_date,
                                                custom_manufacturing_start_date: row.manufacture_date,
                                                expiry_date: row.expired_date,
                                                custom_patient_id: patient,
                                                custom_does: row.does,
                                                custom_volume: row.volume,
                                                custom_uom: row.uom,
                                                item: finished_item,
                                                custom_confirm: row.confirm
                                            }
                                        },
                                        callback: function (r) {
                                            if (r.message) {
                                                if (finished_item_row) {
                                                    finished_item_row.use_serial_batch_fields = 1;
                                                    finished_item_row.batch_no = r.message.name;
                                                }
                                                
                                                // ✅ Show success popup message
                                                frappe.show_alert({
                                                    message: __(`Batch "${batch_id}" has been created successfully for item "${finished_item}"`),
                                                    indicator: 'green'
                                                }, 5);
                                                
                                                resolve();
                                            } else if (r.exc) {
                                                frappe.msgprint(__("Batch creation failed: " + r.exc));
                                                reject();
                                            }
                                        },
                                        error: function(r) {
                                            if (r.exc && r.exc.includes("cannot have Batch")) {
                                                reject(new Error(`Batch not enabled for item ${finished_item}`));
                                            } else {
                                                reject(new Error("Batch creation failed"));
                                            }
                                        }

                                    });
                                }
                            }).catch(error => {
                                console.error("Error checking batch existence:", error);
                                reject();
                            });
                        }).catch(error => {
                            console.error("Error checking item batch settings:", error);
                            frappe.msgprint(__("Error checking item settings. Please try again."));
                            reject();
                        });
                    });

                    promises.push(promise);
                }
            }
        });

        return Promise.all(promises).then(() => {
            frm.refresh_field('custom_manufacture_batch');
            frm.refresh_field('items');
        }).catch(() => {
            // Handle any errors from promises
            console.error("Error in batch creation process");
        });
    }
});

function toggle_manbatch_table(frm) {
    let show_table = false;
    let finished_item = '';

    (frm.doc.items || []).forEach(item => {
        if (item.is_finished_item && item.custom_enable_manufacturing_batch) {
            show_table = true;
            finished_item = item.item_code;
        }
    });

    frm.toggle_display('custom_manufacture_batch', show_table);

    if (show_table && (!frm.doc.custom_manufacture_batch || frm.doc.custom_manufacture_batch.length === 0)) {
        let row = frm.add_child('custom_manufacture_batch');
        row.patient = frm.doc.custom_patient_;
        row.item = finished_item;
        frm.refresh_field('custom_manufacture_batch');
    }
}

frappe.ui.form.on('Stock Entry', {
    refresh: function(frm) {
        // Always show the parent checkbox if from_bom is enabled
        if (frm.doc.from_bom) {
            frm.set_df_property('custom_enable_manufacturing_batch', 'hidden', 0);
        } else {
            frm.set_df_property('custom_enable_manufacturing_batch', 'hidden', 1);
        }
        
        // Toggle manbatch table based on current state
        toggle_manbatch_table(frm);
        
        // Watch for changes in child table checkbox
        frm.fields_dict['items'].grid.wrapper.on(
            'change',
            '.input-with-feedback[data-fieldname="custom_enable_manufacturing_batch"]',
            function () {
                toggle_manbatch_table(frm);
            }
        );
    },
    
    onload_post_render: function (frm) {
        toggle_manbatch_table(frm);
    },
    
    from_bom: function(frm) {
        if (frm.doc.from_bom) {
            // Show the checkbox when from_bom is enabled
            frm.set_df_property('custom_enable_manufacturing_batch', 'hidden', 0);
        } else {
            // Hide and uncheck when from_bom is disabled
            frm.set_df_property('custom_enable_manufacturing_batch', 'hidden', 1);
            frm.set_value('custom_enable_manufacturing_batch', 0);
            
            // Clear child checkboxes
            if (frm.doc.items) {
                frm.doc.items.forEach(row => {
                    frappe.model.set_value(row.doctype, row.name, 'custom_enable_manufacturing_batch', 0);
                });
            }
            frm.refresh_field('items');
        }
        
        toggle_manbatch_table(frm);
    },
    
    custom_enable_manufacturing_batch: function(frm) {
        // When parent checkbox changes, update all child rows
        if (frm.doc.items) {
            frm.doc.items.forEach(row => {
                frappe.model.set_value(
                    row.doctype, 
                    row.name, 
                    'custom_enable_manufacturing_batch', 
                    frm.doc.custom_enable_manufacturing_batch ? 1 : 0
                );
            });
        }
        frm.refresh_field('items');
        
        // Toggle table visibility based on checkbox state
        toggle_manbatch_table(frm);
    }
});

frappe.ui.form.on('Stock Entry Detail', {
    items_add: function(frm, cdt, cdn) {
        // Set child checkbox to match parent when new row is added
        if (frm.doc.custom_enable_manufacturing_batch) {
            frappe.model.set_value(cdt, cdn, 'custom_enable_manufacturing_batch', 1);
        }
        
        // Check if we need to show the manbatch table
        toggle_manbatch_table(frm);
    },
    
    items_remove: function(frm) {
        // Update table visibility
        toggle_manbatch_table(frm);
    },
    
    custom_enable_manufacturing_batch: function(frm, cdt, cdn) {
        toggle_manbatch_table(frm);
    }
});

// ---- Helper Functions ----

function toggle_manbatch_table(frm) {
    let show_table = false;
    let finished_item = '';
    
    // Check if any finished item has the checkbox enabled
    (frm.doc.items || []).forEach(item => {
        if (item.custom_enable_manufacturing_batch) {
            show_table = true;
            finished_item = item.item_code;
        }
    });
    
    // Show/hide the manbatch table
    frm.toggle_display('custom_manufacture_batch', show_table);
    
    if (show_table) {
        // Only add row if table is empty
        if (!frm.doc.custom_manufacture_batch || frm.doc.custom_manufacture_batch.length === 0) {
            let row = frm.add_child('custom_manufacture_batch');
            row.patient = frm.doc.custom_patient_;
            row.item = finished_item;
            frm.refresh_field('custom_manufacture_batch');
        } else {
            // Update existing row with latest data
            frm.doc.custom_manufacture_batch[0].patient = frm.doc.custom_patient_;
            frm.doc.custom_manufacture_batch[0].item = finished_item;
            frm.refresh_field('custom_manufacture_batch');
        }
    } else {
        // Clear table when no finished items have checkbox enabled
        if (frm.doc.custom_manufacture_batch && frm.doc.custom_manufacture_batch.length > 0) {
            frm.clear_table('custom_manufacture_batch');
            frm.refresh_field('custom_manufacture_batch');
        }
    }
}

frappe.ui.form.on('Stock Entry', {
    refresh(frm) {
        highlight_finished_items(frm);
        const grid_wrapper = frm.fields_dict.items.grid.wrapper[0];
        const observer = new MutationObserver(() => {
            highlight_finished_items(frm);
        });
        observer.observe(grid_wrapper, { childList: true, subtree: true });
    },
    onload_post_render(frm) {
        highlight_finished_items(frm);
    },
    items_on_form_rendered(frm) {
        highlight_finished_items(frm);
    }
});

function highlight_finished_items(frm) {
    const grid_rows = frm.fields_dict.items.grid.grid_rows;
    grid_rows.forEach(row => {
        if (row.doc.is_finished_item) {
            row.wrapper.css("background-color", "#fff7ae");
            console.log("row.doc.is_finished_item", row.doc.is_finished_item);
        } else {
            row.wrapper.css("background-color", "");
            console.log("row.doc.is_finished_item", row.doc.is_finished_item);
        }
    });
}

