frappe.ui.form.on('Stock Entry', {
    onload: async function (frm) {
        if (frm.doc.docstatus === 1) return;
        
        const hasMainStorePermission = await check_main_store_permission();
        if (hasMainStorePermission) {
            return;
        }

        const employee = await get_logged_in_employee();
        if (!employee) return;

        const function_codes = await get_employee_function_codes(employee.name);
        frm.set_query('custom_employee_functions', () => ({
            filters: [['name', 'in', function_codes]]
        }));

        if (function_codes.length === 1) {
            frm.set_value('custom_employee_functions', function_codes[0]);
            frm.trigger('custom_employee_functions');
        }
    },

    custom_employee_functions: async function (frm) {
        if (!frm.doc.custom_employee_functions) return;

        const empFunc = await get_employee_function_details(frm.doc.custom_employee_functions);
        if (!empFunc) return;

        // --- 🔹 Fetch details ---
        const lab_warehouses = (empFunc.table_szrn || []).map(r => r.lab_warehouse).filter(Boolean);
        const store_warehouses = (empFunc.table_bukm || []).map(r => r.store_warehouse).filter(Boolean);
        const segments = (empFunc.table_xlgh || []).map(r => r.segment).filter(Boolean);
        const cost_centers = (empFunc.cost_center || []).map(r => r.cost_center).filter(Boolean);

        // --- 🔹 Set queries for Segment & Cost Center ---
        frm.set_query('custom_cost_centre', () => ({
            filters: [['name', 'in', segments.length ? segments : ['__none__']]]
        }));

