            } else {
                return { filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]] };
            }
        };

        // --- 🔹 Copy Segment & Cost Center to all child rows automatically ---
        frm.doc.items.forEach(row => {
            if (frm.doc.custom_cost_centre && !row.custom_cost_centre) {
                frappe.model.set_value(row.doctype, row.name, 'custom_cost_centre', frm.doc.custom_cost_centre);
