                frappe.model.set_value(row.doctype, row.name, 'custom_line_of_business', frm.doc.custom_line_of_business);
            }
        });
    },

    // 🔹 When stock entry type changes, refresh warehouse logic dynamically
    stock_entry_type: function (frm) {
        frm.trigger('custom_employee_functions');
    }
});

