frappe.ui.form.on('Stock Entry', {
    onload: function (frm) {
        frm._last_material_request = frm.doc.custom_material_request;

        if (frm.is_new()) {
            frm.trigger('fetch_material_request_data');
        }
    },

    refresh: function (frm) {
        if (frm.doc.custom_material_request !== frm._last_material_request) {
            console.log("🔄 Detected programmatic change in custom_material_request");

            frm._last_material_request = frm.doc.custom_material_request;
            frm.trigger('fetch_material_request_data');
        }
    },

    custom_material_request: function (frm) {
        console.log("✍️ Detected manual change in custom_material_request");

        frm._last_material_request = frm.doc.custom_material_request;
        frm.trigger('fetch_material_request_data');
    },

    fetch_material_request_data: async function (frm) {
        if (!frm.doc.custom_material_request) {
            console.log("ℹ️ No Material Request linked yet.");
            return;
        }

        try {
            console.log("🔍 Fetching Material Request:", frm.doc.custom_material_request);

            const material_request = await frappe.call({
                method: 'frappe.client.get',
                args: {
                    doctype: 'Material Request',
                    name: frm.doc.custom_material_request
                }
            });

            console.log("✅ Material Request Response:", material_request);

            const func = material_request.message?.custom_employee_function;
            console.log("✅ custom_employee_function:", func);

            if (func) {
                frm.set_value('custom_employee_functions', func);
                
                frm.set_value('custom_default_employee_function', func);
                frm.set_value('custom_target_employee_function', func);
                frm.trigger('custom_employee_functions');

                console.log("👤 Employee function set to:", func);
            } else {
                console.log("⚠️ No custom_employee_function found in Material Request");
            }
        } catch (error) {
            console.error("🚨 Error fetching Material Request:", error);
            frappe.msgprint(__('Error fetching Material Request data'));
        }
    }
});

frappe.ui.form.on('Stock Entry', {
    onload: async function (frm) {
        if (frm.doc.docstatus === 1) return;
        
        // If document is new and has a Material Request, fetch its data first
        if (frm.is_new() && frm.doc.custom_material_request) {
            await frm.trigger('fetch_material_request_data');
            return; // Exit early to prevent overriding
        }

        
        const hasMainStorePermission = await check_main_store_permission();
        if (hasMainStorePermission) {
            return;
        }

        const employee = await get_logged_in_employee();
        if (!employee) return;

        const function_codes = await get_employee_function_codes(employee.name);
        frm.set_query('custom_employee_functions', () => ({
            filters: [['name', 'in', function_codes]]
        }));
        
        frm.set_query('custom_default_employee_function', () => ({
            filters: [['name', 'in', function_codes]]
        }));
        

        if (function_codes.length === 1) {
            frm.set_value('custom_employee_functions', function_codes[0]);
            frm.trigger('custom_employee_functions');
            
            if (frm.doc.stock_entry_type === "Internal Transfer") {
                frm.set_value('custom_default_employee_function', function_codes[0]);
            }
        }
    },

    custom_employee_functions: async function (frm) {
        if (!frm.doc.custom_employee_functions) return;
        if (frm._employee_func_from_mr) return;
        
        if (frm.is_new() && frm.doc.custom_material_request) {
            await frm.trigger('fetch_material_request_data');
            return; // Exit early to prevent overriding
        }


        const empFunc = await get_employee_function_details(frm.doc.custom_employee_functions);
        if (!empFunc) return;

        // --- 🔹 Fetch details ---
        const lab_warehouses = (empFunc.table_szrn || []).map(r => r.lab_warehouse).filter(Boolean);
        const store_warehouses = (empFunc.table_bukm || []).map(r => r.store_warehouse).filter(Boolean);
        const segments = (empFunc.table_xlgh || []).map(r => r.segment).filter(Boolean);
        const cost_centers = (empFunc.cost_center || []).map(r => r.cost_center).filter(Boolean);
        const allowed_projects = (empFunc.project_list || []).map(r => r.projects).filter(Boolean);


        // --- 🔹 Set queries for Segment & Cost Center ---
        frm.set_query('custom_cost_centre', () => ({
            filters: [['name', 'in', segments.length ? segments : ['__none__']]]
        }));

        frm.set_query('custom_line_of_business', () => ({
            filters: [['name', 'in', cost_centers.length ? cost_centers : ['__none__']]]
        }));
        
        frm.set_query('project', () => ({
                filters: [['name', 'in', allowed_projects.length ? allowed_projects : ['__none__']]]
        }));
        
        if (frm.doc.project && allowed_projects.length && !allowed_projects.includes(frm.doc.project)) {
            frm.set_value('project', '');
            frappe.msgprint(__("The selected project is not allowed for this Employee Function."));
        }
        

        // --- 🔹 Warehouse Filtering Logic ---
        const is_transfer_type = ["Material Transfer", "Material Transfer for Manufacture"].includes(frm.doc.stock_entry_type);

        if (is_transfer_type) {
            // 🔹 Transfer Type: Store ➝ Lab
            frm.set_query('from_warehouse', () => ({
                filters: [['name', 'in', store_warehouses.length ? store_warehouses : ['__none__']]]
            }));
            frm.set_query('to_warehouse', () => ({
                filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]]
            }));

            if (!frm.doc.from_warehouse && store_warehouses.length)
                console.log("store_warehouses[0]",store_warehouses[0]);
                frm.set_value('from_warehouse', store_warehouses[0]);
            if (!frm.doc.to_warehouse && lab_warehouses.length)
                frm.set_value('to_warehouse', lab_warehouses[0]);
        } else {
            // 🔹 Other Types: Lab ➝ Lab
            frm.set_query('from_warehouse', () => ({
                filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]]
            }));
            frm.set_query('to_warehouse', () => ({
                filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]]
            }));

            if (!frm.doc.from_warehouse && lab_warehouses.length)
                frm.set_value('from_warehouse', lab_warehouses[0]);
            if (!frm.doc.to_warehouse && lab_warehouses.length)
                frm.set_value('to_warehouse', lab_warehouses[0]);
        }

        // --- 🔹 Apply same logic to Child Table (Stock Entry Detail) ---
        frm.fields_dict.items.grid.get_field('s_warehouse').get_query = function() {
            if (is_transfer_type) {
                return { filters: [['name', 'in', store_warehouses.length ? store_warehouses : ['__none__']]] };
            } else {
                return { filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]] };
            }
        };

        frm.fields_dict.items.grid.get_field('t_warehouse').get_query = function() {
            if (is_transfer_type) {
                return { filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]] };
            } else {
                return { filters: [['name', 'in', lab_warehouses.length ? lab_warehouses : ['__none__']]] };
            }
        };

        // --- 🔹 Copy Segment & Cost Center to all child rows automatically ---
        frm.doc.items.forEach(row => {
            if (frm.doc.custom_cost_centre && !row.custom_cost_centre) {
                frappe.model.set_value(row.doctype, row.name, 'custom_cost_centre', frm.doc.custom_cost_centre);
            }
            if (frm.doc.custom_line_of_business && !row.custom_line_of_business) {
                frappe.model.set_value(row.doctype, row.name, 'custom_line_of_business', frm.doc.custom_line_of_business);
            }
        });
    },
    
    custom_default_employee_function: async function (frm) {
        if (!frm.doc.custom_default_employee_function) return;
        
        if (frm.doc.stock_entry_type === "Internal Transfer") {
            const empFunc = await get_employee_function_details(frm.doc.custom_default_employee_function);
            if (!empFunc) return;

            // Get lab warehouses from default employee function
            const default_lab_warehouses = (empFunc.table_szrn || []).map(r => r.lab_warehouse).filter(Boolean);
            
            // Store in frm for later use
            frm._default_lab_warehouses = default_lab_warehouses;

            // Set from_warehouse filter and value
            frm.set_query('from_warehouse', () => ({
                filters: [['name', 'in', default_lab_warehouses.length ? default_lab_warehouses : ['__none__']]]
            }));

            if (!frm.doc.from_warehouse && default_lab_warehouses.length) {
                frm.set_value('from_warehouse', default_lab_warehouses[0]);
            }

            // Update child table s_warehouse filters
            update_child_warehouse_filters(frm);
        }
    },
    
    custom_target_employee_function: async function (frm) {
        if (!frm.doc.custom_target_employee_function) return;
        
        if (frm.doc.stock_entry_type === "Internal Transfer") {
            const empFunc = await get_employee_function_details(frm.doc.custom_target_employee_function);
            if (!empFunc) return;

            // Get lab warehouses from target employee function
            const target_lab_warehouses = (empFunc.table_szrn || []).map(r => r.lab_warehouse).filter(Boolean);
            
            // Store in frm for later use
            frm._target_lab_warehouses = target_lab_warehouses;

            // Set to_warehouse filter and value
            frm.set_query('to_warehouse', () => ({
                filters: [['name', 'in', target_lab_warehouses.length ? target_lab_warehouses : ['__none__']]]
            }));

            if (!frm.doc.to_warehouse && target_lab_warehouses.length) {
                frm.set_value('to_warehouse', target_lab_warehouses[0]);
                console.log("target_lab_warehouses",target_lab_warehouses[0]);
            }

            // Update child table t_warehouse filters
            update_child_warehouse_filters(frm);
        }
    },

    // 🔹 When stock entry type changes, refresh warehouse logic dynamically
    stock_entry_type: function (frm) {
        frm.trigger('custom_employee_functions');
        if (frm.doc.stock_entry_type === "Internal Transfer") {
            // Trigger both functions to set up filters
            if (frm.doc.custom_default_employee_function) {
                frm.trigger('custom_default_employee_function');
            }
            if (frm.doc.custom_target_employee_function) {
                frm.trigger('custom_target_employee_function');
            }
        } else {
            frm.trigger('custom_employee_functions');
        }
    },
    refresh: function(frm) {
        set_employee_function_mandatory(frm);
    },
    validate: function(frm) {
        if (frm.doc.stock_entry_type === "Internal Transfer") {
            if (!frm.doc.custom_default_employee_function) {
                frappe.throw(__("Default Employee Function is mandatory for Internal Transfer"));
            }
            if (!frm.doc.custom_target_employee_function) {
                frappe.throw(__("Target Employee Function is mandatory for Internal Transfer"));
            }
        }
    }
});

// --- 🔹 Helper function to update child table warehouse filters ---
function update_child_warehouse_filters(frm) {
    if (frm.doc.stock_entry_type !== "Internal Transfer") return;

    const default_lab_warehouses = frm._default_lab_warehouses || [];
    const target_lab_warehouses = frm._target_lab_warehouses || [];

    // Set s_warehouse filter (from default employee function)
    frm.fields_dict.items.grid.get_field('s_warehouse').get_query = function() {
        return { 
            filters: [['name', 'in', default_lab_warehouses.length ? default_lab_warehouses : ['__none__']]] 
        };
    };

    // Set t_warehouse filter (from target employee function)
    frm.fields_dict.items.grid.get_field('t_warehouse').get_query = function() {
        return { 
            filters: [['name', 'in', target_lab_warehouses.length ? target_lab_warehouses : ['__none__']]] 
        };
    };

    frm.fields_dict.items.grid.refresh();
}

// --- 🔹 Set mandatory fields based on stock entry type ---
function set_employee_function_mandatory(frm) {
    const isInternalTransfer = frm.doc.stock_entry_type === "Internal Transfer";

    if (isInternalTransfer) {
        frm.set_df_property('custom_default_employee_function', 'reqd', 1);
        frm.set_df_property('custom_target_employee_function', 'reqd', 1);
        frm.set_df_property('from_warehouse', 'reqd', 1);
        frm.set_df_property('to_warehouse', 'reqd', 1);
    } else {
        console.log("Else condition execution");
    }
}

