function load_expiry_status(frm) {
    if (!frm.doc.items || !frm.doc.items.length) return;
    var item_codes = frm.doc.items.map(function(r) { return r.item_code; });
    fetch('/api/method/get_item_batch_expiry', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'X-Frappe-CSRF-Token': frappe.csrf_token,
            'X-Requested-With': 'XMLHttpRequest'
        },
        credentials: 'same-origin',
        body: JSON.stringify({ item_codes: item_codes })
    })
    .then(r => r.json())
    .then(data => {
        if (data.message) {
            setTimeout(function() { inject_expiry_badges(frm, data.message); }, 1500);
        }
    });
}

function inject_expiry_badges(frm, expiry_map) {
    frm.doc.items.forEach(function(row) {
        var expiry = expiry_map[row.item_code];
        if (!expiry) return;
        var badge_color, badge_bg;
        if (expiry.status === 'expired') {
            badge_color = '#c62828'; badge_bg = '#fdecea';
        } else if (expiry.status === 'expiring_soon') {
            badge_color = '#e65100'; badge_bg = '#fff3e0';
        } else {
            badge_color = '#2e7d32'; badge_bg = '#e8f5e9';
        }
        var badge = '<span class="expiry-badge" style="background:' + badge_bg + ';color:' + badge_color + ';padding:2px 8px;border-radius:20px;font-size:11px;font-weight:800;display:inline-block;margin-top:4px;">' + expiry.label + '</span>';
        var row_el = frm.fields_dict['items'].grid.grid_rows_by_docname[row.name];
        if (row_el && row_el.row) {
            var shortage_col = row_el.row.find('[data-fieldname="shortage"] .static-area');
            if (shortage_col.find('.expiry-badge').length === 0) {
                shortage_col.append(badge);
            }
        }
    });
}

