window.refresh_stock_available = function (frm) {
    let items = frm.doc.material_allocation || [];
    if (!items.length) return;

    let item_codes = items.map(r => r.item_code);
    fetch('/api/method/get_open_pr_po', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-Frappe-CSRF-Token': frappe.csrf_token },
        body: JSON.stringify({ item_codes: item_codes })
    })
        .then(r => r.json())
        .then(data => {
            let pr_po_map = data.message || {};
            items.forEach(function (row) {
                frappe.call({
                    method: 'ma_get_allocated_qty',
                    args: { item_code: row.item_code, employee_function: frm.doc.employee_function, exclude_parent: frm.doc.name, row_name: row.name },
                    callback: function (res) {
                        if (res.message) {
                            let grid_row = frm.fields_dict['material_allocation'].grid.grid_rows_by_docname[row.name];
                            let free_stock = res.message.free_stock || 0;
                            let qty_req = row.quantity_required || 0;
                            let shortage = Math.max(qty_req - free_stock, 0);
                            let pr_po = pr_po_map[row.item_code] || {};

                            if (grid_row) {
                                let allocated = grid_row.doc.qty_allocated || 0;
                                let display_stock = Math.max(free_stock - allocated, 0);  // ← minus qty_allocated

                                grid_row.doc.stock_available = display_stock;
                                grid_row.doc.shortage = Math.max(qty_req - display_stock, 0);
                                grid_row.doc.open_pr = pr_po.open_pr || 0;
                                grid_row.doc.open_po = pr_po.open_po || 0;

                                if (!grid_row.doc.allocate_qty) {
                                    grid_row.doc.allocate_qty = qty_req;
                                }

                                grid_row.refresh_field('stock_available');
                                grid_row.refresh_field('shortage');
                                grid_row.refresh_field('open_pr');
                                grid_row.refresh_field('open_po');
                                grid_row.refresh_field('allocate_qty');
                            }
                        }
                    }
                });
            });
        });
};

window.auto_allocate_all = function (frm) {
    let items = frm.doc.material_allocation || [];
    if (!items.length) return;

    frappe.confirm('⚠️ Warning: Auto Allocation will lock the quantities and update the stock. Continue?', function () {
        let done = 0;
        let promises = [];

        items.forEach(function (row) {
            let p = new Promise((resolve, reject) => {
                frappe.call({
                    method: 'ma_get_allocated_qty',
                    args: { item_code: row.item_code, employee_function: frm.doc.employee_function, exclude_parent: frm.doc.name, row_name: row.name },
                    callback: function (res) {
                        let fresh_stock = (res.message && res.message.free_stock) || 0;
                        let qty_to_transfer = fresh_stock >= (row.allocate_qty || 0)
                            ? (row.quantity_required || 0)
                            : Math.min(fresh_stock, row.quantity_required || 0);

                        frappe.model.set_value('Material Allocation Item', row.name, 'qty_allocated', qty_to_transfer)
                            .then(() => {
                                return frappe.model.set_value('Material Allocation Item', row.name, 'allocate_qty', qty_to_transfer);
                            })
                            .then(() => {
                                resolve();
                            })
                            .catch(reject);
                    }
                });
            });
            promises.push(p);
        });

        Promise.all(promises).then(() => {
            frm._allocating = true;
            frm.save().then(() => {
                // Save qty_allocated to DB for each row explicitly to ensure persistence
                let save_promises = items.map(row =>
                    frappe.call({
                        method: 'frappe.client.set_value',
                        args: {
                            doctype: 'Material Allocation Item',
                            name: row.name,
                            fieldname: 'qty_allocated',
                            value: row.qty_allocated
                        }
                    })
                );

                Promise.all(save_promises).then(() => {
                    frappe.call({
                        method: 'frappe.client.set_value',
                        args: { 
                            doctype: 'Material Allocation', 
                            name: frm.doc.name, 
                            fieldname: 'allocation_status', 
                            value: 'Allocated' 
                        },
                        callback: function () {
                            frappe.show_alert({ message: '✅ Auto Allocation done! Quantities are now locked.', indicator: 'green' });
                            setTimeout(function () { frm.reload_doc(); }, 1000);
                        }
                    });
                });
            });
        });
    });
};

