// Updates both stock_available AND allocate_qty — called from button only
function auto_allocate_all(frm) {
    let items = frm.doc.items || [];
    if (!items.length) { frappe.msgprint("Koi items nahi hain!"); return; }
    let done = 0;
    items.forEach(function(row) {
        frappe.call({
            method: 'ma_get_allocated_qty',
            args: {
                item_code: row.item_code,
                warehouse: frm.doc.warehouse,
                exclude_parent: frm.doc.name,
                row_name: row.name
            },
            callback: function(res) {
                if (res.message) {
                    frappe.model.set_value(row.doctype, row.name, 'allocate_qty',    res.message.allocate_qty || 0);
                    frappe.model.set_value(row.doctype, row.name, 'stock_available', res.message.free_stock || 0);
                }
                done++;
                if (done === items.length) {
                    frappe.show_alert({ message: '✅ Auto Allocation done!', indicator: 'green' });
                    setTimeout(function() { frm.reload_doc(); }, 1000);
                }
            }
        });
    });
}

frappe.ui.form.on('Stock Entry', {
    refresh: function (frm) {
        toggle_manbatch_table(frm);

        frm.fields_dict['items'].grid.wrapper.on(
            'change',
            '.input-with-feedback[data-fieldname="custom_enable_manufacturing_batch"]',
            function () {
                toggle_manbatch_table(frm);
            }
        );
    },

    onload_post_render: function (frm) {
        toggle_manbatch_table(frm);
    },

    // ✅ Re-evaluate table visibility when stock_entry_type changes
    stock_entry_type: function (frm) {
        toggle_manbatch_table(frm);
    },

    before_save: function (frm) {
        let promises = [];

        (frm.doc.custom_manufacture_batch || []).forEach(row => {
            let patient = frm.doc.custom_patient_;
            row.patient = patient;

            // Find finished item
            let finished_item = '';
            let finished_item_row = null;
            (frm.doc.items || []).forEach(item => {
                if (item.is_finished_item) {
                    finished_item = item.item_code;
                    finished_item_row = item;
                }
            });
            row.item = finished_item;

            // ✅ Only create batch for "Manufacture" type, skip for everything else
            if (frm.doc.stock_entry_type !== "Manufacture") {
                return;
            }

            // ✅ Validate Expiry Date is mandatory
            if (!row.expired_date) {
                frappe.throw(__("Expiry Date is mandatory to create a Batch."));
            }

            // ✅ Validate Manufacture Date is mandatory
            if (!row.manufacture_date) {
                frappe.throw(__("Manufacture Date is mandatory to create a Batch."));
            }

            // ✅ Validate that Expiry Date is in the future
            let today = frappe.datetime.now_date();
            if (row.expired_date < today) {
                frappe.throw(__("Expiry Date cannot be in the past."));
            }

            // ✅ Validate Manufacture Date is before Expiry Date
            let mfg_date = frappe.datetime.str_to_obj(row.manufacture_date);
            let exp_date = frappe.datetime.str_to_obj(row.expired_date);
            if (mfg_date >= exp_date) {
                frappe.throw(__("Manufacture Date must be before Expiry Date."));
            }

            if (row.manufacture_date && row.manufacture_batch) {
                if (!finished_item) {
                    frappe.throw(__("No finished item found. Cannot create batch."));
                    return;
                }

                let batch_id = row.manufacture_batch;
                if (!batch_id) {
                    frappe.throw(__("Manufacture Batch ID is required."));
                    return;
                }

                // ✅ Only create batch if not already linked
                if (!finished_item_row.batch_no) {
                    let promise = new Promise((resolve, reject) => {
                        // ✅ Check if the item has batch enabled
                        frappe.db.get_value("Item", finished_item, ["has_batch_no", "item_name"]).then(item_result => {
                            if (!item_result.message || !item_result.message.has_batch_no) {
                                frappe.msgprint({
                                    title: __('Batch Not Enabled'),
                                    indicator: 'red',
                                    message: __(`The finished item "${item_result.message?.item_name || finished_item}" must have "Has Batch No" enabled in the Item master to create batches.`)
                                });
                                reject();
                                return;
                            }

                            // ✅ Check if batch already exists
                            frappe.db.get_value("Batch", {
                                "batch_id": batch_id,
                                "item": finished_item
                            }, "name").then(result => {
                                if (result.message && result.message.name) {
                                    frappe.throw(__(`Batch ID "${batch_id}" already exists for item "${finished_item}". Please use a different Batch ID.`));
                                    reject();
                                } else {
                                    frappe.call({
                                        method: "frappe.client.insert",
                                        args: {
                                            doc: {
                                                doctype: "Batch",
                                                batch_id: batch_id,
                                                manufacturing_date: row.manufacture_date,
                                                custom_manufacturing_start_date: row.manufacture_date,
                                                expiry_date: row.expired_date,
                                                custom_patient_id: patient,
                                                custom_does: row.does,
                                                custom_volume: row.volume,
                                                custom_uom: row.uom,
                                                item: finished_item,
                                                custom_confirm: row.confirm
                                            }
                                        },
                                        callback: function (r) {
                                            if (r.message) {
                                                if (finished_item_row) {
                                                    finished_item_row.use_serial_batch_fields = 1;
                                                    finished_item_row.batch_no = r.message.name;
                                                }

                                                frappe.show_alert({
                                                    message: __(`Batch "${batch_id}" has been created successfully for item "${finished_item}"`),
                                                    indicator: 'green'
                                                }, 5);

                                                resolve();
                                            } else if (r.exc) {
                                                frappe.msgprint(__("Batch creation failed: " + r.exc));
                                                reject();
                                            }
                                        },
                                        error: function (r) {
                                            if (r.exc && r.exc.includes("cannot have Batch")) {
                                                reject(new Error(`Batch not enabled for item ${finished_item}`));
                                            } else {
                                                reject(new Error("Batch creation failed"));
                                            }
                                        }
                                    });
                                }
                            }).catch(error => {
                                console.error("Error checking batch existence:", error);
                                reject();
                            });
                        }).catch(error => {
                            console.error("Error checking item batch settings:", error);
                            frappe.msgprint(__("Error checking item settings. Please try again."));
                            reject();
                        });
                    });

                    promises.push(promise);
                }
            }
        });

        return Promise.all(promises).then(() => {
            frm.refresh_field('custom_manufacture_batch');
            frm.refresh_field('items');
        }).catch(() => {
            console.error("Error in batch creation process");
        });
    }
});

function toggle_manbatch_table(frm) {
    // ✅ Exact type strings from your ERPNext system
    let allowed_types = ["Manufacture", "Consumption For Manufacturing"];

    if (!allowed_types.includes(frm.doc.stock_entry_type)) {
        frm.toggle_display('custom_manufacture_batch', false);
        return;
    }

    let show_table = false;
    let finished_item = '';

    (frm.doc.items || []).forEach(item => {
        if (item.custom_enable_manufacturing_batch) {
            show_table = true;
            if (item.is_finished_item) {
                finished_item = item.item_code;
            } else if (!finished_item) {
                finished_item = item.item_code;
            }
        }
    });

    frm.toggle_display('custom_manufacture_batch', show_table);

    if (show_table && (!frm.doc.custom_manufacture_batch || frm.doc.custom_manufacture_batch.length === 0)) {
        let row = frm.add_child('custom_manufacture_batch');
        row.patient = frm.doc.custom_patient_;
        row.item = finished_item;
        frm.refresh_field('custom_manufacture_batch');
    }
}

frappe.ui.form.on('Stock Entry', {
    refresh: function(frm) {
        frm.doc.items.forEach(function(row) {
            if (row.custom_oligo_bank_ref) {
                if (!row.oligo_bank) {
                    frappe.model.set_value(row.doctype, row.name, 'oligo_bank', row.custom_oligo_bank_ref);
                    console.log("Source oligo_bank auto-filled on refresh for row", row.name, ":", row.custom_oligo_bank_ref);
                }
                if (!row.to_oligo_bank) {
                    frappe.model.set_value(row.doctype, row.name, 'to_oligo_bank', row.custom_oligo_bank_ref);
                    console.log("to_oligo_bank auto-filled on refresh for row", row.name, ":", row.custom_oligo_bank_ref);
                }
            }
        });
        frm.fields_dict.items.grid.refresh();
    },

    before_save: function(frm) {
        frm.doc.items.forEach(function(row) {
            if (row.custom_oligo_bank_ref) {
                if (row.oligo_bank !== row.custom_oligo_bank_ref) {
                    frappe.model.set_value(row.doctype, row.name, 'oligo_bank', row.custom_oligo_bank_ref);
                    console.log("Source oligo_bank set before save for row", row.name, ":", row.custom_oligo_bank_ref);
                }
                if (row.to_oligo_bank !== row.custom_oligo_bank_ref) {
                    frappe.model.set_value(row.doctype, row.name, 'to_oligo_bank', row.custom_oligo_bank_ref);
                    console.log("to_oligo_bank set before save for row", row.name, ":", row.custom_oligo_bank_ref);
                }
            } else {
                if (row.oligo_bank) {
                    frappe.model.set_value(row.doctype, row.name, 'oligo_bank', '');
                }
                if (row.to_oligo_bank) {
                    frappe.model.set_value(row.doctype, row.name, 'to_oligo_bank', '');
                }
                console.log("Oligo banks cleared before save for row", row.name);
            }
        });
        frm.fields_dict.items.grid.refresh();
    },

    validate: async function(frm) {
        console.log("🔍 Starting Stock Entry validation...");

        const oligoTypes = [
            "RG-Peptide",
            "RG-Gene Synthesis",
            "RG-Duplex DNA Oligos",
            "RG-ASO",
            "RG-siRNA",
            "RG-gRNA",
            "RG-Probe",
            "RG-Primers"
        ];

        const itemDetailsCache = {};
        let mandatoryErrors = [];

        for (const row of frm.doc.items || []) {
            console.log("➡️ Validating row:", row.name, "Item:", row.item_code);

            let itemChildGroup = null;

            if (itemDetailsCache[row.item_code]) {
                itemChildGroup = itemDetailsCache[row.item_code];
            } else {
                try {
                    const itemDoc = await frappe.db.get_doc('Item', row.item_code);
                    itemChildGroup = itemDoc.item_chid_group;
                    itemDetailsCache[row.item_code] = itemChildGroup;
                    console.log("🧬 Fetched item_chid_group:", itemChildGroup);
                } catch (e) {
                    console.error("❌ Failed to fetch Item doc for", row.item_code, e);
                    continue;
                }
            }

            const isOligoType = oligoTypes.includes(itemChildGroup);

            // ✅ Mandatory check
            if (isOligoType && !row.custom_oligo_bank_ref) {
                mandatoryErrors.push(
                    `Row ${row.idx}: <b>Oligo Bank Ref</b> is mandatory for item <b>${row.item_code}</b>`
                );
                continue;
            }

            // ✅ Validate selected oligo bank belongs to this item
            if (isOligoType && row.custom_oligo_bank_ref) {
                try {
                    const oligoDoc = await frappe.db.get_doc('Oligo Bank', row.custom_oligo_bank_ref);
                    console.log("🧬 Fetched Oligo Bank doc:", oligoDoc);

                    if (oligoDoc.item !== row.item_code) {
                        mandatoryErrors.push(
                            `Row ${row.idx}: Oligo Bank <b>${row.custom_oligo_bank_ref}</b> (linked to item <b>${oligoDoc.item}</b>) does not match item <b>${row.item_code}</b>. Please select a valid Oligo Bank for this item.`
                        );
                    }
                } catch (e) {
                    console.error("❌ Failed to fetch Oligo Bank doc for", row.custom_oligo_bank_ref, e);
                    mandatoryErrors.push(
                        `Row ${row.idx}: Could not verify Oligo Bank <b>${row.custom_oligo_bank_ref}</b>. Please check if it exists.`
                    );
                }
            }
        }

        if (mandatoryErrors.length > 0) {
            frappe.validated = false;
            frappe.msgprint({
                title: __('Oligo Bank Validation Failed'),
                indicator: 'red',
                message: mandatoryErrors.join('<br><br>')
            });
            return;
        }

        console.log("✅ Stock Entry validation completed successfully");
    }
});


