// Global variable to store hidden warehouses
let hidden_warehouses_list = [];

frappe.ui.form.on('Stock Entry', {
    onload: function(frm) {
        setup_s_warehouse_filter(frm);
    },
    
    refresh: function(frm) {
        setup_s_warehouse_filter(frm);
    },
    
    before_save: function(frm) {
