function setup_s_warehouse_filter(frm) {
    // Check if current user has 'Main Store' role
    let user_roles = frappe.user_roles || [];
    let has_main_store = user_roles.includes('Main Store');
    
    console.log('=== Setting up Warehouse Filter ===');
    console.log('User Roles:', user_roles);
    console.log('Has Main Store Role:', has_main_store);
    
    if (!has_main_store) {
        // User does NOT have Main Store role - apply filter
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Warehouse',
                fields: ['name', 'custom_main_store'],
                limit_page_length: 0
            },
            callback: function(r) {
                if (r.message) {
                    // Get hidden warehouses (custom_main_store checked)
                    hidden_warehouses_list = r.message.filter(function(w) {
                        return w.custom_main_store === 1 || 
                               w.custom_main_store === '1' || 
                               w.custom_main_store === true;
                    }).map(function(w) {
                        return w.name;
                    });
                    
                    console.log('Hidden Warehouses (should not show):', hidden_warehouses_list);
                    console.log('Total Warehouses:', r.message.length);
                    console.log('Hidden Count:', hidden_warehouses_list.length);
                    
                    // Set query for s_warehouse with NOT IN filter
                    frm.set_query('s_warehouse', 'items', function(doc, cdt, cdn) {
                        if (hidden_warehouses_list.length > 0) {
                            return {
                                filters: [
                                    ['Warehouse', 'name', 'not in', hidden_warehouses_list]
                                ]
                            };
                        } else {
                            return {};
                        }
                    });
                    
                    // Set query for t_warehouse with NOT IN filter
                    frm.set_query('t_warehouse', 'items', function(doc, cdt, cdn) {
                        if (hidden_warehouses_list.length > 0) {
                            return {
                                filters: [
                                    ['Warehouse', 'name', 'not in', hidden_warehouses_list]
                                ]
                            };
                        } else {
                            return {};
                        }
                    });
                    
                    // Set query for custom_group_warehouse (form level field)
                    if (frm.fields_dict.custom_group_warehouse) {
                        frm.set_query('custom_group_warehouse', function() {
                            if (hidden_warehouses_list.length > 0) {
                                return {
                                    filters: [
                                        ['Warehouse', 'name', 'not in', hidden_warehouses_list]
                                    ]
                                };
                            } else {
                                return {};
                            }
                        });
                        console.log('✅ Filter applied to custom_group_warehouse');
                    } else {
                        console.warn('⚠️ custom_group_warehouse field not found');
                    }
                    
                    console.log('✅ Filter applied successfully to s_warehouse, t_warehouse and custom_group_warehouse');
                    frm.refresh_field('items');
                    frm.refresh_field('custom_group_warehouse');
                    frm.refresh_field('items');
                }
            }
        });
    } else {
        // User HAS Main Store role - show all warehouses
        console.log('✅ User has Main Store role - No filter needed');
        hidden_warehouses_list = [];
        
        frm.set_query('s_warehouse', 'items', function() {
            return {};
        });
        
        frm.set_query('t_warehouse', 'items', function() {
            return {};
        });
        
        frm.set_query('custom_group_warehouse', function() {
            return {};
        });
        
        frm.refresh_field('items');
        frm.refresh_field('custom_group_warehouse');
        
        frm.refresh_field('items');
    }
}

function validate_s_warehouse_selection(frm, cdt, cdn) {
    // Only validate if user doesn't have Main Store role
    if (hidden_warehouses_list.length === 0) {
        return;
    }
    
    let row = locals[cdt][cdn];
    
    if (row.s_warehouse && hidden_warehouses_list.includes(row.s_warehouse)) {
        frappe.model.set_value(cdt, cdn, 's_warehouse', '');
        frappe.msgprint({
            title: __('Access Denied'),
            message: __('You do not have permission to select the main warehouse: <b>{0}</b>', [row.s_warehouse]),
            indicator: 'red'
        });
    }
}

function validate_t_warehouse_selection(frm, cdt, cdn) {
    // Only validate if user doesn't have Main Store role
    if (hidden_warehouses_list.length === 0) {
        return;
    }
    
    let row = locals[cdt][cdn];
    
    if (row.t_warehouse && hidden_warehouses_list.includes(row.t_warehouse)) {
        frappe.model.set_value(cdt, cdn, 't_warehouse', '');
        frappe.msgprint({
            title: __('Access Denied'),
            message: __('You do not have permission to select the main warehouse: <b>{0}</b>', [row.t_warehouse]),
            indicator: 'red'
        });
    }
}

function validate_custom_group_warehouse(frm) {
    // Only validate if user doesn't have Main Store role
    if (hidden_warehouses_list.length === 0) {
        return;
    }
    
    if (frm.doc.custom_group_warehouse && hidden_warehouses_list.includes(frm.doc.custom_group_warehouse)) {
        frm.set_value('custom_group_warehouse', '');
        frappe.msgprint({
            title: __('Access Denied'),
            message: __('You do not have permission to select the main warehouse: <b>{0}</b>', [frm.doc.custom_group_warehouse]),
            indicator: 'red'
        });
    }
}

function validate_warehouses(frm) {
    // Skip validation if user has Main Store role
    if (hidden_warehouses_list.length === 0) {
        return true;
    }
    
    let invalid_items = [];
    
    // Check custom_group_warehouse field
    if (frm.doc.custom_group_warehouse && hidden_warehouses_list.includes(frm.doc.custom_group_warehouse)) {
        invalid_items.push({
            location: 'Group Warehouse Field',
            warehouse: frm.doc.custom_group_warehouse
        });
    }
    
    // Check item table warehouses
    frm.doc.items.forEach(function(row, idx) {
        // Check s_warehouse
        if (row.s_warehouse && hidden_warehouses_list.includes(row.s_warehouse)) {
            invalid_items.push({
                location: `Row ${idx + 1} - Source Warehouse`,
                warehouse: row.s_warehouse
            });
        }
        
        // Check t_warehouse
        if (row.t_warehouse && hidden_warehouses_list.includes(row.t_warehouse)) {
            invalid_items.push({
                location: `Row ${idx + 1} - Target Warehouse`,
                warehouse: row.t_warehouse
            });
        }
    });
    
    if (invalid_items.length > 0) {
        let msg = '<b>Following fields have restricted warehouses:</b><br><br>';
        invalid_items.forEach(function(item) {
            msg += `• ${item.location}: ${item.warehouse}<br>`;
        });
        
        frappe.msgprint({
            title: __('Cannot Save'),
            message: __(msg),
            indicator: 'red'
        });
        
        frappe.validated = false;
        return false;
    }
    
    return true;
}
